INSERT INTO sim_scenario_drones (
    scenario_id, drone_no, model_id, serial_no,
    initial_lat, initial_lon, initial_alt, initial_battery_pct,
    initial_rssi, role_tag
) VALUES (
    #{scenarioId}, #{droneNo}, #{modelId}, #{serialNo},
    #{initialLat}, #{initialLon}, #{initialAlt}, #{initialBatteryPct},
    #{initialRssi}, #{roleTag}
)

INSERT INTO sim_scenario_links (
    scenario_id, src_drone_no, dst_drone_no, initial_quality, is_enabled
) VALUES (
    #{scenarioId}, #{srcDroneNo}, #{dstDroneNo}, #{initialQuality}, #{isEnabled}
)
